            return 0;  /* error: longjmp landed here */                       \
        }                                                                    \
        return name##_orig(fcinfo);                                          \
    }

WRAP(float4pl)  WRAP(float4mi)  WRAP(float4mul)  WRAP(float4div)
WRAP(float8pl)  WRAP(float8mi)  WRAP(float8mul)  WRAP(float8div)

#undef WRAP

